1	/**
2	 * 공통 유틸리티 및 이미지 관리
3	 * member.html, non_member.html에서 로드됨
4	 */
5	
6	// ============================================
7	// 이미지 경로 관리
8	// ============================================
9	
10	const CAR_IMGS = {
11	  g80:      '../assets/images/g80.png',
12	  bmw5:     '../assets/images/bmw5.png',
13	  k8:       '../assets/images/k8.png',
14	  grandeur: '../assets/images/grandeur.png',
15	  sorento:  '../assets/images/sorento.png',
16	  tucson:   '../assets/images/tucson.png',
17	  nx350h:   '../assets/images/nx350h.png',
18	  santafe:  '../assets/images/santafe.png',
19	};
20	
21	// ============================================
22	// 자연어 검색 기능
23	// ============================================
24	
25	let searchQueries = [];
26	let searchDebounceTimer = null;
27	
28	/**
29	 * 검색 초기화 - 페이지 로드 시 실행
30	 * search_data.js에서 로드된 데이터 사용
31	 */
32	function initSearch() {
33	  // search_data.js에서 SEARCH_QUERIES를 전역으로 제공
34	  if (typeof SEARCH_QUERIES !== 'undefined') {
35	    searchQueries = SEARCH_QUERIES;
36	    console.log('검색 질의 로드됨:', searchQueries.length, '개');
37	    return true;
38	  } else {
39	    console.error('SEARCH_QUERIES 데이터를 찾을 수 없습니다. search_data.js가 로드되었나요?');
40	    return false;
41	  }
42	}
43	
44	/**
45	 * 검색 입력 핸들러 (디바운스 적용)
46	 */
47	function handleSearchInput(inputValue) {
48	  clearTimeout(searchDebounceTimer);
49	
50	  searchDebounceTimer = setTimeout(() => {
51	    performSearch(inputValue);
52	  }, 500); // 0.5초 디바운스
53	}
54	
55	/**
56	 * 검색 수행
57	 */
58	async function performSearch(query) {
59	  const cleanQuery = query.trim().toLowerCase();
60	
61	  // 빈 검색: 기본 상태로 복귀
62	  if (!cleanQuery) {
63	    showDefaultResults();
64	    return;
65	  }
66	
67	  // 키워드 토크나이즈
68	  const keywords = cleanQuery.split(/\s+/);
69	
70	  // 각 질의와 매칭 점수 계산
71	  const matches = searchQueries.map(q => {
72	    const intersection = keywords.filter(k =>
73	      q.keywords.some(qk => qk.includes(k) || k.includes(qk.substring(0, 2)))
74	    );
75	    return {
76	      ...q,
77	      score: intersection.length
78	    };
79	  }).filter(m => m.score > 0);
80	
81	  // 점수 높은 순으로 정렬
82	  matches.sort((a, b) => b.score - a.score);
83	
84	  if (matches.length === 0) {
85	    showNoResults(keywords);
86	  } else {
87	    await displaySearchResults(matches);
88	  }
89	}
90	
91	/**
92	 * 검색 결과 표시 (복수 결과셋)
93	 * search_data.js의 SEARCH_RESULTS 객체에서 데이터 직접 사용
94	 */
95	function displaySearchResults(matches) {
96	  const resultsContainer = document.getElementById('search-results-container');
97	
98	  if (!resultsContainer) {
99	    console.error('검색 결과 컨테이너 없음');
100	    return;
101	  }
102	
103	  // 기본 추천 섹션 숨기기
104	  const recommendedSection = document.getElementById('recommended-section');
105	  if (recommendedSection) {
106	    recommendedSection.style.display = 'none';
107	  }
108	
109	  resultsContainer.innerHTML = '';
110	  resultsContainer.style.display = 'block';
111	
112	  // 각 결과셋 렌더링
113	  for (const match of matches) {
114	    if (typeof SEARCH_RESULTS !== 'undefined' && SEARCH_RESULTS[match.id]) {
115	      const resultData = SEARCH_RESULTS[match.id];
116	      const section = createSearchResultSection(resultData, match.score);
117	      resultsContainer.appendChild(section);
118	    } else {
119	      console.error(`결과셋을 찾을 수 없음 (${match.id})`);
120	    }
121	  }
122	}
123	
124	/**
125	 * 검색 결과 섹션 HTML 생성 (car-grid 2열 형식)
126	 */
127	function createSearchResultSection(resultData, score) {
128	  const section = document.createElement('div');
129	  section.className = 'search-result-section';
130	  section.innerHTML = `
131	    <div class="search-result-header">
132	      <h3>${resultData.title}</h3>
133	      <p class="search-result-desc">${resultData.description}</p>
134	    </div>
135	    <div class="car-grid" id="search-grid-${resultData.queryId}">
136	      ${resultData.cars.map(car => `
137	        <div class="car-card" onclick="viewDetails('${car.img}')">
138	          <div class="car-img">
139	            <img src="${CAR_IMGS[car.img]}" alt="${car.name}" style="max-width:100%; max-height:100%; object-fit:contain;">
140	            <span class="img-tag ${car.tagC}">${car.tag}</span>
141	            <div class="img-btns">
142	              <button class="ib" onclick="viewDetails('${car.img}'); event.stopPropagation();">상세</button>
143	              <button class="ib" onclick="selectProduct('${car.img}'); event.stopPropagation();">선택</button>
144	            </div>
145	          </div>
146	          <div class="car-info">
147	            <div class="car-brand">${car.brand}</div>
148	            <div class="car-name">${car.name}</div>
149	            <div class="car-spec">${car.spec}</div>
150	            <div class="price-row">
151	              <span class="price">${car.price}</span>
152	            </div>
153	            <div class="price-sub">${car.sub}</div>
154	            <div style="font-size:10px;color:#1a56db;margin-top:5px;font-weight:700;">★ ${car.highlight}</div>
155	          </div>
156	        </div>
157	      `).join('')}
158	    </div>
159	  `;
160	
161	  return section;
162	}
163	
164	/**
165	 * 검색 결과 없음 표시
166	 */
167	function showNoResults(keywords) {
168	  const resultsContainer = document.getElementById('search-results-container');
169	
170	  if (!resultsContainer) return;
171	
172	  const recommendedSection = document.getElementById('recommended-section');
173	  if (recommendedSection) {
174	    recommendedSection.style.display = 'none';
175	  }
176	
177	  resultsContainer.innerHTML = `
178	    <div class="search-no-result">
179	      <div class="no-result-icon">🔍</div>
180	      <div class="no-result-text">"${keywords.join(' ')}"에 맞는 검색 결과가 없습니다.</div>
181	      <div class="no-result-subtitle">다른 검색어를 시도해보세요.</div>
182	      <div class="search-suggestions">
183	        <div class="suggestion-title">추천 검색어:</div>
184	        <div class="suggestion-chips">
185	          ${searchQueries.map(q => `
186	            <div class="suggestion-chip" onclick="document.querySelector('#search-input').value='${q.label}'; handleSearchInput('${q.label}')">
187	              ${q.description}
188	            </div>
189	          `).join('')}
190	        </div>
191	      </div>
192	    </div>
193	  `;
194	
195	  resultsContainer.style.display = 'block';
196	}
197	
198	/**
199	 * 기본 상태로 복귀 (검색창 비움)
200	 */
201	function showDefaultResults() {
202	  const resultsContainer = document.getElementById('search-results-container');
203	  const recommendedSection = document.getElementById('recommended-section');
204	
205	  if (resultsContainer) {
206	    resultsContainer.style.display = 'none';
207	  }
208	
209	  if (recommendedSection) {
210	    recommendedSection.style.display = 'block';
211	  }
212	}
213	
214	/**
215	 * 상품 선택 핸들러
216	 */
217	function selectProduct(imgKey) {
218	  alert(`${imgKey.toUpperCase()} 차량이 선택되었습니다.\n금융상품 안내로 이동합니다.`);
219	  // TODO: 금융상품 페이지로 이동
220	}
221	
222	/**
223	 * 상품 상세 보기 핸들러
224	 */
225	function viewDetails(imgKey) {
226	  // 현재는 기본 alert (추후 모달로 변경 가능)
227	  const carInfo = {
228	    g80: 'GENESIS G80 3.5T AWD 스포츠패키지 - 380마력',
229	    bmw5: 'BMW 5시리즈 530i xDrive M스포츠 - 252마력',
230	    k8: 'KIA K8 3.5 GDI 시그니처 - 300마력',
231	    grandeur: 'HYUNDAI 그랜저 캘리그래피 3.5 GDI - 304마력',
232	    sorento: 'KIA 쏘렌토 하이브리드 시그니처 - 7인승, 연비 16.0km/L',
233	    tucson: 'HYUNDAI 투싼 하이브리드 인스퍼레이션 - 연비 15.6km/L',
234	    nx350h: 'LEXUS NX 350h F SPORT - 연비 14.6km/L',
235	    santafe: 'HYUNDAI 싼타페 하이브리드 캘리그래피 - 7인승, 연비 14.2km/L'
236	  };
237	
238	  alert(carInfo[imgKey] || '차량 정보를 찾을 수 없습니다.');
239	}
